namespace sv_20b5467638e24865a0f739d039e38db9.Components;

public enum ScreenSize
{
    Mobile,
    Tablet,
    Desktop
}

using Microsoft.JSInterop;

namespace sv_20b5467638e24865a0f739d039e38db9.Components;

public sealed class ScreenSizeInterop : IAsyncDisposable
{
    internal const string ModulePath = "./Components/ScreenSizeProvider.razor.js";
    internal const string InitMethod = "initialize";
    internal const string DisposeMethod = "dispose";

    private readonly IJSRuntime _js;
    private IJSObjectReference? _module;

    public ScreenSizeInterop(IJSRuntime js) => _js = js;

    private async ValueTask<IJSObjectReference> GetModuleAsync()
        => _module ??= await _js.InvokeAsync<IJSObjectReference>("import", ModulePath);

    public async ValueTask InitializeAsync(DotNetObjectReference<ScreenSizeProvider> dotNetRef)
    {
        var module = await GetModuleAsync();
        await module.InvokeVoidAsync(InitMethod, dotNetRef);
    }

    public async ValueTask DisposeAsync()
    {
        try
        {
            if (_module is not null)
            {
                await _module.InvokeVoidAsync(DisposeMethod);
                await _module.DisposeAsync();
            }
        }
        catch (JSDisconnectedException) { }
    }
}

@implements IAsyncDisposable
@inject IJSRuntime JS

<CascadingValue Value="_screenSize" Name="ScreenSize">
    @ChildContent
</CascadingValue>

@code {
    [Parameter]
    public RenderFragment? ChildContent { get; set; }

    private ScreenSize _screenSize = ScreenSize.Desktop;
    private ScreenSizeInterop? _interop;
    private DotNetObjectReference<ScreenSizeProvider>? _dotNetRef;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            _interop = new ScreenSizeInterop(JS);
            _dotNetRef = DotNetObjectReference.Create(this);
            await _interop.InitializeAsync(_dotNetRef);
        }
    }

    [JSInvokable]
    public async Task OnScreenSizeChanged(string category)
    {
        var newSize = category switch
        {
            "Mobile" => ScreenSize.Mobile,
            "Tablet" => ScreenSize.Tablet,
            _ => ScreenSize.Desktop
        };

        if (newSize != _screenSize)
        {
            await InvokeAsync(() =>
